/// <summary>
/// Main method executed when the class is triggered via the system menu or startup configuration.
/// </summary>
/// <param name="_args">Arguments passed to the method.</param>
public static void main(Args _args)
{
    PurchLine           purchLine = PurchLine::findRecId(5637365826);        

    ETGSPAINUnsoldInventTrans::findOrCreateByRefRecIdandQty(5637422829, purchLine.PurchQty, purchLine.PurchUnit, purchLine, true);
}
